 185→router.get('/getFollowsData', async(req, res) => {
 186→    const {userId, loggedInUserId} = req.query;
 187→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 188→    // console.log(req.query)
 189→    try {
 190→        const followersCountPromise = supabase
 191→        .from('follows')
 192→        .select('*', {count: 'exact', head: true})
 193→        .eq('following_id', userId);
 194→
 195→        const followingCountPromise = supabase
 196→        .from('follows')
 197→        .select('*', {count: 'exact', head: true})
 198→        .eq('follower_id', userId)
 199→
 200→        const isFollowingPromise = supabase
 201→        .from('follows')
 202→        .select('*', {count: 'exact', head: true})
 203→        .eq('follower_id', loggedInUserId)
 204→        .eq('following_id', userId)
 205→
 206→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 207→            followersCountPromise, followingCountPromise, isFollowingPromise,
 208→        ])
 209→
 210→
 211→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 212→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 213→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 214→
 215→        if(errorFollowers || errorFollowings || errorIsfollowing){
 216→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 217→            return res.status(500).json({error: 'failed to fetch data'})
 218→        }
 219→
 220→        return res.status(200).json({
 221→            followersCount: followersCount,
 222→            followingsCount: followingsCount,
 223→            isFollowing: isFollowingCount > 0
 224→        })
 225→
 226→    } catch (error) {
 227→        console.error('Error in Promise.all:', error);
 228→        res.status(500).json({ error: 'An unexpected error occurred' });
 229→    }
 230→
 231→})
