 374→router.get('/getUnreadNotification', requireAuth, async(req, res) => {
 375→    const {limit, before} = req.query;
 376→
 377→    const parsedLimit = parseInt(limit);
 378→    if(isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 20){
 379→        return res.status(400).json({error: 'limit must be between 1 and 20'});
 380→    }
 381→
 382→    const receiverId = req.userId;
 383→    const fetchLimit = parsedLimit + 1;
 384→
 385→    let journalQuery = supabase
 386→    .from('notifications')
 387→    .select(`
 388→        *,
 389→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count)),
 390→        users!sender_id(name, user_email, image_url, id, badge)
 391→        `)
 392→    .eq('receiver_id', receiverId)
 393→    .eq('read', false)
 394→    .order('created_at', {ascending: false})
 395→    .order('id', {ascending: false})
 396→    .limit(fetchLimit)
 397→
 398→    let opinionQuery = supabase
 399→    .from('notification_opinions')
 400→    .select(`
 401→        *,
 402→        opinions!opinion_id(id, opinion, user_id, created_at),
 403→        users!sender_id(name, user_email, image_url, id, badge)
 404→        `)
 405→    .eq('receiver_id', receiverId)
 406→    .eq('read', false)
 407→    .order('created_at', {ascending: false})
 408→    .order('id', {ascending: false})
 409→    .limit(fetchLimit)
 410→
 411→    if(before){
 412→        journalQuery = journalQuery.lt('created_at', before);
 413→        opinionQuery = opinionQuery.lt('created_at', before);
 414→    }
 415→
 416→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 417→
 418→    if(journalResult.error){
 419→        console.error('supabase error:', journalResult.error.message);
 420→        return res.status(500).json({error: 'supabase error while getting unread notification'})
 421→    }
 422→    if(opinionResult.error){
 423→        console.error('supabase error:', opinionResult.error.message);
 424→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
 425→    }
 426→
 427→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 428→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 429→
 430→    const merged = [...journalNotifs, ...opinionNotifs]
 431→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 432→
 433→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 434→
 435→    let hasLikedResult = [];
 436→    let hasBookMarkedResult = [];
 437→    if(journalIds.length > 0){
 438→        const [hasLiked, hasBookMarked] = await Promise.all([
 439→            supabase.from('likes').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds),
 440→            supabase.from('bookmarks').select('journal_id').eq('user_id', receiverId).in('journal_id', journalIds)
 441→        ]);
 442→
 443→        if(hasLiked.error || hasBookMarked.error){
 444→            console.error('error', hasLiked.error || hasBookMarked.error)
 445→            return res.status(500).json({error: 'supabase error on likes or bookmarks table'})
 446→        }
 447→        hasLikedResult = hasLiked.data || [];
 448→        hasBookMarkedResult = hasBookMarked.data || [];
 449→    }
 450→
 451→    const userHasLikedSet = new Set(hasLikedResult.map((like) => like.journal_id));
 452→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmark) => bookmark.journal_id));
 453→
 454→    const formatted = merged.map((notification) =>({
 455→        ...notification,
 456→        hasLiked: notification.source === 'journal' ? userHasLikedSet.has(notification?.journal_id) : false,
 457→        hasBookMarked: notification.source === 'journal' ? userHasBookmarkedSet.has(notification?.journal_id) : false
 458→    }))
 459→
 460→    const hasMore = formatted.length > parsedLimit;
 461→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 462→
 463→    return res.status(200).json({
 464→        data: slicedData,
 465→        hasMore: hasMore
